import { useState } from 'react';
import './App.css';
import Api from './axios/api';

interface Usuario {
  id: number;
  nome: string;
}

function App() {
const [usuario, setUsuario] =useState<Usuario[]>([{} as Usuario]);
const BuscarTodosUsuarios= async () => {
  console.log("Buscando todos os usuários...");
  await Api.get("",{
    params:{
    planilha:"usuario"
  }
  }
).then((response)=>{
    setUsuario(response.data)
    console.log(usuario);
  }
  )  
  .catch((e)=> console.log(e));
}

  return (
    <div style={container}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>      
    <div style={{display:"flex",backgroundColor:"blue", color:"white", padding:"20px"}}>

        {usuario.map((usuario)=>{
          return(  
            <div>         
              <h1>{usuario.id}</h1>
              </div>

          )
        })}

    </div>
<div>
      <button onClick={BuscarTodosUsuarios}>  Visuaisar</button>
      </div>
    </div>
  );
}

export default App;

const container={
  display:"flex",
  color:"black",
  backgroundColor:"red",
  alignItems:"center",
  justifyContent:"center",
 }
